def fairness_weighted_aggregate(tools):
    weights = {}
    for tool in tools:
        bias_score = calculate_bias_score(tool)
        fairness_weight = 1 / (1 + bias_score)
        weights[tool.id] = fairness_weight

    # Weighted majority vote
    weighted_votes = {}
    for tool in tools:
        for category, vote in tool.categories.items():
            weighted_votes[category] = weighted_votes.get(category, 0) + weights[tool.id] * vote

    return weighted_votes

