function biasCorrectionMiddleware(toolResponse: any): any {
  const corrected = { ...toolResponse };

  if (corrected.content?.[0]?.text) {
    const text = corrected.content[0].text;
    const demographics = extractDemographics(text);

    // Enforce minimum representation
    Object.entries(demographics).forEach(([group, count]) => {
      if (count < 0.1 * Object.values(demographics).reduce((a, b) => a + b, 0)) {
        corrected.content[0].text += `\n[FAIRNESS NOTE: Added representation for ${group}]`;
      }
    });
  }

  return corrected;
}

// Wrap Claude tool responses
